"use client"

import { useState, useEffect, useRef } from "react"

interface TypewriterTextProps {
    text: string
    speed?: number  // 瘥?蝚行神蝘
    onComplete?: () => void
    className?: string
    children?: React.ReactNode  // ?冽皜脫? (?交?桀???)
}

/**
 * ?剁? ?箸??璈??r
 * 
 * 雿輻 requestAnimationFrame ?芸??
 * ?芷＊蝷箇???嚗?瘣拇??蝪賢?
 */
export default function TypewriterText({
    text,
    speed = 20,
    onComplete,
    className,
    children
}: TypewriterTextProps) {
    const [displayedText, setDisplayedText] = useState("")
    const [isComplete, setIsComplete] = useState(false)
    const indexRef = useRef(0)
    const lastTimeRef = useRef(0)
    const rafRef = useRef<number | null>(null)

    // ?蔭?嗆?摮霈?
    useEffect(() => {
        indexRef.current = 0
        lastTimeRef.current = 0
        setDisplayedText("")
        setIsComplete(false)
    }, [text])

    // ?敺芰
    useEffect(() => {
        if (!text || isComplete) return

        const animate = (timestamp: number) => {
            if (!lastTimeRef.current) lastTimeRef.current = timestamp

            const elapsed = timestamp - lastTimeRef.current

            if (elapsed >= speed) {
                const currentIndex = indexRef.current

                if (currentIndex < text.length) {
                    // 銝甈⊿＊蝷箏???蝚虫誑??r
                    const charsToAdd = Math.min(
                        Math.ceil(elapsed / speed),
                        text.length - currentIndex
                    )

                    setDisplayedText(text.slice(0, currentIndex + charsToAdd))
                    indexRef.current = currentIndex + charsToAdd
                    lastTimeRef.current = timestamp

                    rafRef.current = requestAnimationFrame(animate)
                } else {
                    // 摰?
                    setIsComplete(true)
                    onComplete?.()
                }
            } else {
                rafRef.current = requestAnimationFrame(animate)
            }
        }

        rafRef.current = requestAnimationFrame(animate)

        return () => {
            if (rafRef.current) {
                cancelAnimationFrame(rafRef.current)
            }
        }
    }, [text, speed, onComplete, isComplete])

    // 憒???children嚗 render props 璅∪?
    if (children && typeof children === "function") {
        return (children as (text: string) => React.ReactNode)(displayedText)
    }

    // ?身嚗?交葡??摮r
    return (
        <span className={className}>
            {displayedText}
            {!isComplete && (
                <span className="animate-pulse">??/span>
            )}
        </span>
    )
}

/**
 * 敺?rawParts 銝剖??冽??憿舐內??摮r
 * ?蕪??thought_signature ?隞頂蝯梯?閮r
 */
export function extractDisplayableText(rawParts: { text?: string; thought?: string }[]): string {
    if (!rawParts || !Array.isArray(rawParts)) return ""

    // ?芣???text 甈?嚗蕭??thought/thought_signature
    return rawParts
        .filter(part => part.text && !part.thought)
        .map(part => part.text)
        .join("")
}

"use client"

import { AlertCircle, Wallet, Ticket, Info } from "lucide-react"

interface DailyTipsProps {
    day: number
    notes?: any[]
    costs?: any[]
    tickets?: any[]
}

export default function DailyTips({ day, notes, costs, tickets }: DailyTipsProps) {
    // 憒?瘝?隞颱?鞈?撠曹?憿舐內
    if ((!notes || notes.length === 0) && (!costs || costs.length === 0) && (!tickets || tickets.length === 0)) {
        return null
    }

    return (
        <div className="mx-5 mb-6 space-y-4">
            {/* ?? 瘥瘜冽?鈭? */}
            {notes && notes.length > 0 && (
                <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
                    <div className="flex items-center gap-2 mb-3 text-amber-700">
                        <AlertCircle className="w-4 h-4" />
                        <h4 className="text-sm font-bold">瘥????</h4>
                    </div>
                    <div className="space-y-3">
                        {notes.map((note, idx) => (
                            <div key={idx} className="flex gap-3 items-start">
                                <div className="text-lg leading-none mt-0.5">{note.icon || '??'}</div>
                                <div>
                                    <div className="text-sm font-bold text-slate-800">{note.title}</div>
                                    <div className="text-xs text-slate-600 mt-0.5 whitespace-pre-line">{note.content}</div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* ? ?摯?梯祥 */}
                {costs && costs.length > 0 && (
                    <div className="bg-slate-50 border border-slate-200 rounded-xl p-4">
                        <div className="flex items-center gap-2 mb-3 text-slate-600">
                            <Wallet className="w-4 h-4" />
                            <h4 className="text-sm font-bold">?摯?梯祥</h4>
                        </div>
                        <div className="space-y-2">
                            {costs.map((cost, idx) => (
                                <div key={idx} className="flex justify-between items-center text-sm border-b border-slate-100 last:border-0 pb-2 last:pb-0">
                                    <span className="text-slate-600 font-medium">{cost.item}</span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-800">{cost.amount}</div>
                                        {cost.note && <div className="text-[10px] text-slate-400">{cost.note}</div>}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* ? 鈭日巨??*/}
                {tickets && tickets.length > 0 && (
                    <div className="bg-blue-50 border border-blue-100 rounded-xl p-4">
                        <div className="flex items-center gap-2 mb-3 text-blue-700">
                            <Ticket className="w-4 h-4" />
                            <h4 className="text-sm font-bold">鈭日巨??/h4>
                        </div>
                        <div className="space-y-2">
                            {tickets.map((ticket, idx) => (
                                <div key={idx} className="bg-white/60 rounded-lg p-2 text-sm border border-blue-100">
                                    <div className="font-bold text-slate-800 flex justify-between">
                                        {ticket.name}
                                        <span className="text-blue-600">{ticket.price}</span>
                                    </div>
                                    {ticket.note && <div className="text-xs text-slate-500 mt-1">{ticket.note}</div>}
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

"use client"

import { MapContainer, TileLayer, Marker, Popup, Polyline, useMap } from "react-leaflet"
import "leaflet/dist/leaflet.css"
import L from "leaflet"
import { useEffect, useState } from "react"
import { Bus, Car, Footprints } from "lucide-react"

// ?芾?璅? Icon
const createNumberedIcon = (number: number, color = "#0f172a") => {
    return L.divIcon({
        className: "custom-marker",
        html: `<div style="background-color: ${color}; color: white; width: 28px; height: 28px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: bold; border: 3px solid white; box-shadow: 0 2px 8px rgba(0,0,0,0.3); font-size: 12px;">${number}</div>`,
        iconSize: [28, 28],
        iconAnchor: [14, 14],
    })
}

// ?芸?蝮格?啣?隞交項????
function FitBounds({ markers }: { markers: any[] }) {
    const map = useMap()
    useEffect(() => {
        if (markers.length > 0) {
            const group = new L.FeatureGroup(markers.map((m) => L.marker([m.lat, m.lng])))
            map.fitBounds(group.getBounds().pad(0.15))
        }
    }, [markers, map])
    return null
}

// 頝舐?閬? Hook
function useRoute(markersKey: string, markers: any[], mode: string) {
    const [route, setRoute] = useState<[number, number][]>([])
    const [routeInfo, setRouteInfo] = useState<{ distance: string; duration: string } | null>(null)
    const [loading, setLoading] = useState(false)

    useEffect(() => {
        if (markers.length < 2) {
            setRoute([])
            setRouteInfo(null)
            return
        }

        const fetchRoute = async () => {
            setLoading(true)
            try {
                // 撱箇?摨扳?摮葡 (OSRM ?澆?: lng,lat;lng,lat;...)
                const coords = markers.map(m => `${m.lng},${m.lat}`).join(';')

                // OSRM profile: foot (甇亥?), car (??), bike (?唾?頠?
                const profile = mode === 'walk' ? 'foot' : mode === 'drive' ? 'car' : 'foot'

                const res = await fetch(
                    `https://router.project-osrm.org/route/v1/${profile}/${coords}?overview=full&geometries=geojson`
                )
                const data = await res.json()

                if (data.routes && data.routes.length > 0) {
                    const geometry = data.routes[0].geometry.coordinates
                    // GeoJSON 摨扳???[lng, lat]嚗?閬?? [lat, lng]
                    setRoute(geometry.map((c: number[]) => [c[1], c[0]] as [number, number]))

                    // 閮??????兝r
                    const distanceKm = (data.routes[0].distance / 1000).toFixed(1)
                    const durationMin = Math.round(data.routes[0].duration / 60)
                    setRouteInfo({
                        distance: `${distanceKm} km`,
                        duration: durationMin < 60 ? `${durationMin} ??` : `${Math.floor(durationMin / 60)}h ${durationMin % 60}m`
                    })
                }
            } catch (e) {
                console.error("Route fetch error:", e)
            } finally {
                setLoading(false)
            }
        }

        fetchRoute()
    }, [markersKey, mode]) // 雿輻蝛拙???markersKey ?? markers ???

    return { route, routeInfo, loading }
}

// 頝舐?憿撠
const routeColors = {
    walk: "#22c55e",    // 蝬 - 甇亥?
    drive: "#3b82f6",   // ? - ??
    transit: "#f59e0b", // 璈 - 憭抒?撓
}

interface DayMapProps {
    activities: any[]
}

export default function DayMap({ activities }: DayMapProps) {
    const [mode, setMode] = useState<'walk' | 'drive' | 'transit'>('walk')

    // ?蕪?箸?摨扳??暺r
    const markers = activities
        .filter(a => a.lat && a.lng)
        .map((a, index) => ({
            ...a,
            number: index + 1
        }))

    // 撱箇?蝛拙???key ?踹? useEffect ?⊿?閫貊
    const markersKey = markers.map(m => `${m.lat},${m.lng}`).join('|')

    const { route, routeInfo, loading } = useRoute(markersKey, markers, mode)

    if (markers.length === 0) {
        return (
            <div className="rounded-xl border border-dashed border-slate-300 bg-slate-50 h-48 w-full flex flex-col items-center justify-center text-slate-400">
                <div className="text-3xl mb-2">?儭?/div>
                <div className="text-sm font-bold">?怎?啣?鞈?</div>
                <div className="text-xs mt-1">瘣餃??閬漣璅??賡＊蝷箄楝蝺?</div>
                <div className="text-[10px] mt-2 text-slate-300">?內嚗楊頛舀暑?蒂???圈?隞亦?漣璅?/div>
            </div>
        )
    }

    const center = [markers[0].lat, markers[0].lng] as [number, number]

    return (
        <div className="space-y-2">
            {/* 鈭日芋撘? */}
            <div className="flex items-center justify-between">
                <div className="flex gap-1 bg-slate-100 rounded-lg p-1">
                    <button
                        onClick={() => setMode('walk')}
                        className={`flex items-center gap-1 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${mode === 'walk' ? 'bg-white shadow text-green-600' : 'text-slate-500 hover:text-slate-700'
                            }`}
                    >
                        <Footprints className="w-3.5 h-3.5" />
                        甇亥?
                    </button>
                    <button
                        onClick={() => setMode('drive')}
                        className={`flex items-center gap-1 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${mode === 'drive' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'
                            }`}
                    >
                        <Car className="w-3.5 h-3.5" />
                        ??
                    </button>
                    <button
                        onClick={() => setMode('transit')}
                        className={`flex items-center gap-1 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${mode === 'transit' ? 'bg-white shadow text-amber-600' : 'text-slate-500 hover:text-slate-700'
                            }`}
                    >
                        <Bus className="w-3.5 h-3.5" />
                        憭抒?撓
                    </button>
                </div>

                {/* 頝舐?鞈? */}
                {routeInfo && (
                    <div className="flex items-center gap-3 text-xs">
                        <span className="text-slate-500">?? {routeInfo.distance}</span>
                        <span className="text-slate-500">?梧? {routeInfo.duration}</span>
                        {loading && <span className="text-amber-500 animate-pulse">頛銝?..</span>}
                    </div>
                )}
            </div>

            {/* ?啣?摰孵 */}
            <div className="rounded-xl overflow-hidden border border-slate-200 shadow-sm h-72 w-full z-0 relative">
                <MapContainer center={center} zoom={13} scrollWheelZoom={true} className="h-full w-full">
                    <TileLayer
                        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
                        url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
                    />

                    {/* 頝舐?蝜芾ˊ */}
                    {route.length > 0 && (
                        <Polyline
                            positions={route}
                            pathOptions={{
                                color: routeColors[mode],
                                weight: 5,
                                opacity: 0.8,
                                dashArray: mode === 'transit' ? '10, 10' : undefined,
                            }}
                        />
                    )}

                    {/* 璅?暺?*/}
                    {markers.map((m, idx) => {
                        const isFirst = idx === 0
                        const isLast = idx === markers.length - 1
                        const color = isFirst ? "#22c55e" : isLast ? "#ef4444" : "#0f172a"

                        return (
                            <Marker key={m.id || m.place} position={[m.lat, m.lng]} icon={createNumberedIcon(m.number, color)}>
                                <Popup>
                                    <div className="min-w-[150px]">
                                        <div className="font-bold text-sm">{m.number}. {m.place}</div>
                                        {m.time && <div className="text-xs text-slate-500 mt-1">?? {m.time}</div>}
                                        {m.desc && <div className="text-xs text-slate-600 mt-1">{m.desc}</div>}
                                        <a
                                            href={`https://www.google.com/maps/dir/?api=1&destination=${m.lat},${m.lng}`}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="block mt-2 text-xs text-blue-500 hover:underline"
                                        >
                                            ?? ??Google Maps ??撠
                                        </a>
                                    </div>
                                </Popup>
                            </Marker>
                        )
                    })}

                    <FitBounds markers={markers} />
                </MapContainer>
            </div>

            {/* ?? */}
            <div className="flex items-center justify-center gap-4 text-[10px] text-slate-400">
                <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-full bg-green-500"></span> 韏琿?</span>
                <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-full bg-slate-800"></span> ??</span>
                <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-full bg-red-500"></span> 蝯?</span>
            </div>
        </div>
    )
}

"use client"

import { useEffect, useState, useRef, useCallback } from "react"
import Map, { Marker, Popup, Source, Layer, NavigationControl } from "react-map-gl/maplibre"
import type { MapRef, LngLatBoundsLike } from "react-map-gl/maplibre"
import "maplibre-gl/dist/maplibre-gl.css"
import { Bus, Car, Footprints } from "lucide-react"

// 頝舐?憿撠
const routeColors = {
    walk: "#22c55e",    // 蝬 - 甇亥?
    drive: "#3b82f6",   // ? - ??
    transit: "#f59e0b", // 璈 - 憭抒?撓
}

// API ?箇?頝臬?
const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000"

// 頝舐?閬? Hook (雿輻敺垢 /api/route 隞??)
function useRoute(markersKey: string, markers: any[], mode: string, optimize: boolean = false) {
    const [route, setRoute] = useState<GeoJSON.Feature | null>(null)
    const [routeInfo, setRouteInfo] = useState<{ distance: string; duration: string; source?: string } | null>(null)
    const [loading, setLoading] = useState(false)

    useEffect(() => {
        if (markers.length < 2) {
            setRoute(null)
            setRouteInfo(null)
            return
        }

        const fetchRoute = async () => {
            setLoading(true)

            // ???? markers
            const stopsPayload = markers.map(m => ({ lat: m.lat, lng: m.lng, name: m.place }))

            // 撽?摨扳????吭r
            const validStops = stopsPayload.filter(s =>
                s.lat && s.lng &&
                typeof s.lat === 'number' && typeof s.lng === 'number' &&
                s.lat !== 0 && s.lng !== 0
            )

            if (validStops.length < 2) {
                console.warn("?? [Route Debug] 撠 2 ???漣璅?頝喲?頝舐?閮?")
                setRoute(null)
                setRouteInfo(null)
                setLoading(false)
                return
            }

            // ?? 瑼Ｘ葫頝典??楝蝺?(頝典?/頝冽絲) - 蝺臬漲撌株???5 摨西??箄楊??r
            const lats = validStops.map(s => s.lat)
            const latSpan = Math.max(...lats) - Math.min(...lats)

            if (latSpan > 5) {
                console.warn("?? [Route Debug] 頝典??楝蝺?(蝺臬漲撌?", latSpan.toFixed(2), "摨?嚗蝙?函蝺?")
                // ?? 蝜芾ˊ?渡?????? (??銵函內?郊銵楝蝺?
                const straightLineRoute: GeoJSON.Feature = {
                    type: "Feature",
                    properties: {},
                    geometry: {
                        type: "LineString",
                        coordinates: validStops.map(s => [s.lng, s.lat])
                    }
                }
                setRoute(straightLineRoute)
                setRouteInfo({
                    distance: "頝典??

straight-line"
                })
                setLoading(false)
                return
            }

            try {
                const res = await fetch(`${API_BASE}/api/route`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        stops: validStops,  // ?芸???漣璅r
                        mode,
                        optimize
                    })
                })

                if (!res.ok) {
                    const errorText = await res.text()
                    console.error("??[Route Debug] API Error:", res.status, errorText)
                    throw new Error(`Route API failed: ${res.status}`)
                }

                const data = await res.json()

                if (data.route) {
                    setRoute(data.route)
                    setRouteInfo({
                        distance: data.distance,
                        duration: data.duration,
                        source: data.source
                    })
                }
            } catch (e) {
                console.error("??[Route Debug] Fetch error:", e)
                // ??摰嚗??方楝蝺?銝援瞏豹r
                setRoute(null)
                setRouteInfo(null)
            } finally {
                setLoading(false)
            }
        }

        fetchRoute()
    }, [markersKey, mode, optimize])

    return { route, routeInfo, loading }
}

interface DayMapProps {
    activities: any[]
}

export default function DayMap({ activities }: DayMapProps) {
    const mapRef = useRef<MapRef>(null)
    const [mode, setMode] = useState<'walk' | 'drive' | 'transit'>('walk')
    const [popupInfo, setPopupInfo] = useState<any>(null)
    const [mapLoaded, setMapLoaded] = useState(false)  // ?? ?啣?頛??r

    // ?蕪?箸?摨扳??暺r
    const markers = activities
        .filter(a => a.lat && a.lng)
        .map((a, index) => ({
            ...a,
            number: index + 1
        }))

    const markersKey = markers.map(m => `${m.lat},${m.lng}`).join('|')
    const { route, routeInfo, loading } = useRoute(markersKey, markers, mode)

    // ?芸?蝮格?唳???
    const fitBounds = useCallback(() => {
        if (markers.length === 0 || !mapRef.current || !mapLoaded) return  // ?? 瑼Ｘ mapLoaded

        if (markers.length === 1) {
            mapRef.current.flyTo({
                center: [markers[0].lng, markers[0].lat],
                zoom: 15
            })
            return
        }

        const lngs = markers.map(m => m.lng)
        const lats = markers.map(m => m.lat)
        const bounds: LngLatBoundsLike = [
            [Math.min(...lngs), Math.min(...lats)],
            [Math.max(...lngs), Math.max(...lats)]
        ]

        mapRef.current.fitBounds(bounds, { padding: 60, duration: 500 })
    }, [markers, mapLoaded])  // ?? ? mapLoaded 靘陷

    useEffect(() => {
        const timer = setTimeout(fitBounds, 100)
        return () => clearTimeout(timer)
    }, [fitBounds])

    if (markers.length === 0) {
        return (
            <div className="rounded-xl border border-dashed border-slate-300 bg-slate-50 h-48 w-full flex flex-col items-center justify-center text-slate-400">
                <div className="text-3xl mb-2">?儭?/div>
                <div className="text-sm font-bold">?怎?啣?鞈?</div>
                <div className="text-xs mt-1">瘣餃??閬漣璅??賡＊蝷箄楝蝺?</div>
                <div className="text-[10px] mt-2 text-slate-300">?內嚗楊頛舀暑?蒂???圈?隞亦?漣璅?/div>
            </div>
